import React, { useState } from 'react';

const NovoRelatorioTVpA = () => {
  const [form, setForm] = useState({
    campo1: '',
    campo2: '',
    campo3: '',
    campo4: '',
    campo5: '',
    campo6: '',
    campo7: '',
    campo8: ''
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Aqui você pode enviar os dados para a API ou tratar como desejar
    alert('Relatório enviado!');
  };

  return (
    <div>
      <h2>Novo Relatório TVpA</h2>
      <form onSubmit={handleSubmit}>
        <input name="campo1" value={form.campo1} onChange={handleChange} placeholder="Campo 1" /><br />
        <input name="campo2" value={form.campo2} onChange={handleChange} placeholder="Campo 2" /><br />
        <input name="campo3" value={form.campo3} onChange={handleChange} placeholder="Campo 3" /><br />
        <input name="campo4" value={form.campo4} onChange={handleChange} placeholder="Campo 4" /><br />
        <input name="campo5" value={form.campo5} onChange={handleChange} placeholder="Campo 5" /><br />
        <input name="campo6" value={form.campo6} onChange={handleChange} placeholder="Campo 6" /><br />
        <input name="campo7" value={form.campo7} onChange={handleChange} placeholder="Campo 7" /><br />
        <input name="campo8" value={form.campo8} onChange={handleChange} placeholder="Campo 8" /><br />
        <button type="submit">Enviar</button>
      </form>
    </div>
  );
};

export default NovoRelatorioTVpA;
